exports.generatePayroll = (req, res) => {
  const { month } = req.body; // YYYY-MM

  const tx = db.transaction(() => {
    const staff = db.prepare("SELECT id, full_name, base_salary FROM medical_staff WHERE status = 'active'").all();

    for (const s of staff) {
      const baseSalary = s.base_salary || 0;
      const dailyRate = baseSalary / 30;

      const adjustments = db.prepare(`
        SELECT type, amount FROM hr_financials 
        WHERE staff_id = ? AND strftime('%Y-%m', date) = ?
      `).all(s.id, month);

      const currentBonuses = adjustments.filter(a => a.type === 'bonus').reduce((acc, a) => acc + a.amount, 0);
      const currentFinesAdjust = adjustments.filter(a => a.type === 'fine' || a.type === 'loan').reduce((acc, a) => acc + a.amount, 0);

      const leaves = db.prepare("SELECT start_date, end_date FROM hr_leaves WHERE staff_id = ? AND status = 'approved'").all(s.id);
      const isExcused = (dateStr) => {
          const d = new Date(dateStr);
          d.setHours(12,0,0,0);
          return leaves.some(l => {
              const start = new Date(l.start_date);
              const end = new Date(l.end_date);
              start.setHours(12,0,0,0);
              end.setHours(12,0,0,0);
              return d >= start && d <= end;
          });
      };

      const attendance = db.prepare(`
        SELECT status, date FROM hr_attendance 
        WHERE staff_id = ? AND strftime('%Y-%m', date) = ?
      `).all(s.id, month);

      const unexcusedAbsences = attendance.filter(a => a.status === 'absent' && !isExcused(a.date)).length;
      const lateCount = attendance.filter(a => a.status === 'late').length;
      const currentAttendanceFines = (unexcusedAbsences * dailyRate) + (Math.floor(lateCount / 2) * (dailyRate * 0.5));

      const totalDeservedFines = currentFinesAdjust + currentAttendanceFines;
      const totalDeservedBonuses = currentBonuses;
      const targetNet = Math.max(0, baseSalary + totalDeservedBonuses - totalDeservedFines);

      const existingRecords = db.prepare("SELECT SUM(net_salary) as totalNet, SUM(base_salary) as totalBase, SUM(total_bonuses) as totalBonuses, SUM(total_fines) as totalFines FROM hr_payroll WHERE staff_id = ? AND month = ?").get(s.id, month);

      const accountedNet = existingRecords.totalNet || 0;
      const accountedBase = existingRecords.totalBase || 0;
      const accountedBonuses = existingRecords.totalBonuses || 0;
      const accountedFines = existingRecords.totalFines || 0;

      const deltaNet = targetNet - accountedNet;
      const deltaBase = baseSalary - accountedBase;
      const deltaBonuses = totalDeservedBonuses - accountedBonuses;
      const deltaFines = totalDeservedFines - accountedFines;

      if (Math.abs(deltaNet) > 0.01) {
          const existingDraft = db.prepare("SELECT id FROM hr_payroll WHERE staff_id = ? AND month = ? AND status = 'draft'").get(s.id, month);

          if (existingDraft) {
            db.prepare(`
              UPDATE hr_payroll SET 
                base_salary = base_salary + ?, 
                total_bonuses = total_bonuses + ?, 
                total_fines = total_fines + ?, 
                net_salary = net_salary + ?,
                generated_at = datetime('now')
              WHERE id = ?
            `).run(deltaBase, deltaBonuses, deltaFines, deltaNet, existingDraft.id);
          } else {
            db.prepare(`
              INSERT INTO hr_payroll (staff_id, month, base_salary, total_bonuses, total_fines, net_salary, status, generated_at)
              VALUES (?, ?, ?, ?, ?, ?, 'draft', datetime('now'))
            `).run(s.id, month, deltaBase, deltaBonuses, deltaFines, deltaNet);
          }
      }
    }
  });

  try {
    tx();
    res.json({ success: true, message: 'Payroll delta calculations completed.' });
  } catch(e) {
    console.error(e);
    res.status(500).json({ error: e.message });
  }
};

exports.updatePayrollStatus = (req, res) => {
    const { id } = req.params;
    const { status, paymentMethod, transactionRef, notes } = req.body;

    const tx = db.transaction(() => {
        const record = db.prepare(`
            SELECT p.*, m.full_name as staffName 
            FROM hr_payroll p 
            JOIN medical_staff m ON p.staff_id = m.id 
            WHERE p.id = ?
        `).get(id);

        if (!record) throw new Error('Record not found.');

        // Update Payroll Table
        db.prepare(`
            UPDATE hr_payroll 
            SET status = ?, 
                payment_method = ?, 
                transaction_ref = ?, 
                payment_notes = ?, 
                payment_date = datetime('now') 
            WHERE id = ?
        `).run(status, paymentMethod || null, transactionRef || null, notes || null, id);

        // Sync with Treasury if marked as Paid
        if (status === 'paid') {
            // FIX: Explicitly including 'details' column to match billing controller pattern
            // and ensure parameter counts match the Prepare statement exactly.
            db.prepare(`
                INSERT INTO transactions (type, category, amount, method, reference_id, details, date, description)
                VALUES ('expense', 'Staff Salaries', ?, ?, ?, ?, datetime('now'), ?)
            `).run(
                record.net_salary, 
                paymentMethod || 'Cash', 
                id,
                JSON.stringify({ month: record.month, transactionRef: transactionRef || 'N/A' }),
                `Salary Disbursement for ${record.staffName} (${record.month})`
            );
        }
    });

    try {
        tx();
        res.json({ success: true });
    } catch(e) {
        console.error('Payroll status update error:', e);
        res.status(500).json({ error: e.message });
    }
};

const { db } = require('../config/database');

exports.getAll = (req, res) => {
  try {
    const bills = db.prepare(`
      SELECT 
        b.id, b.bill_number as billNumber, b.total_amount as totalAmount, 
        b.paid_amount as paidAmount, b.status, b.bill_date as date,
        p.full_name as patientName, p.id as patientId, p.phone as patientPhone,
        COALESCE(a.status, l.status, o.status, adm.status) as serviceStatus
      FROM billing b
      JOIN patients p ON b.patient_id = p.id
      LEFT JOIN appointments a ON a.bill_id = b.id
      LEFT JOIN lab_requests l ON l.bill_id = b.id
      LEFT JOIN operations o ON o.bill_id = b.id
      LEFT JOIN admissions adm ON adm.bill_id = b.id
      ORDER BY b.bill_date DESC
    `).all();

    const billsWithItems = bills.map(bill => {
      const items = db.prepare('SELECT description, amount FROM billing_items WHERE billing_id = ?').all(bill.id);
      return { ...bill, items };
    });

    res.json(billsWithItems);
  } catch (err) {
    console.error('Error fetching billing records:', err);
    res.status(500).json({ error: 'Failed to fetch billing records' });
  }
};

exports.create = (req, res) => {
  const { patientId, totalAmount, items } = req.body;
  const billNumber = Math.floor(10000000 + Math.random() * 90000000).toString();

  const createTransaction = db.transaction(() => {
    // Explicitly set bill_date to avoid any potential NULLs
    const info = db.prepare(`
      INSERT INTO billing (bill_number, patient_id, total_amount, status, bill_date)
      VALUES (?, ?, ?, 'pending', datetime('now'))
    `).run(billNumber, patientId, totalAmount);

    const billId = info.lastInsertRowid;
    const insertItem = db.prepare('INSERT INTO billing_items (billing_id, description, amount) VALUES (?, ?, ?)');
    for (const item of items) {
      insertItem.run(billId, item.description, item.amount);
    }
    return { id: billId, billNumber, ...req.body, date: new Date().toISOString() };
  });

  try {
    const result = createTransaction();
    res.status(201).json(result);
  } catch (err) {
    res.status(400).json({ error: err.message });
  }
};

exports.recordPayment = (req, res) => {
  const { amount, method, details, date } = req.body;
  const { id } = req.params;

  const bill = db.prepare('SELECT total_amount, paid_amount, bill_number FROM billing WHERE id = ?').get(id);
  if (!bill) return res.status(404).json({ error: 'Bill not found' });

  const newPaid = bill.paid_amount + amount;
  const newStatus = newPaid >= bill.total_amount - 0.01 ? 'paid' : 'partial';

  const tx = db.transaction(() => {
    db.prepare('UPDATE billing SET paid_amount = ?, status = ? WHERE id = ?').run(newPaid, newStatus, id);

    db.prepare(`
      INSERT INTO transactions (type, category, amount, method, reference_id, details, date, description)
      VALUES ('income', 'Bill Payment', ?, ?, ?, ?, ?, ?)
    `).run(amount, method, id, JSON.stringify(details || {}), date || new Date().toISOString(), `Payment for Bill #${bill.bill_number}`);

    if (newStatus === 'paid') {
      db.prepare("UPDATE appointments SET billing_status = 'paid' WHERE bill_id = ?").run(id);
      db.prepare("UPDATE appointments SET status = 'confirmed' WHERE bill_id = ? AND status = 'pending'").run(id);
      db.prepare("UPDATE lab_requests SET status = 'confirmed' WHERE bill_id = ?").run(id);
      db.prepare("UPDATE operations SET status = 'confirmed' WHERE bill_id = ?").run(id);
      const adm = db.prepare("SELECT * FROM admissions WHERE bill_id = ?").get(id);
      if (adm) {
        db.prepare("UPDATE admissions SET status = 'active' WHERE id = ?").run(adm.id);
        db.prepare("UPDATE beds SET status = 'occupied' WHERE id = ?").run(adm.bed_id);
        db.prepare("UPDATE patients SET type = 'inpatient' WHERE id = ?").run(adm.patient_id);
      }
      const paidBillDetails = db.prepare("SELECT is_settlement_bill, settlement_for_patient_id FROM billing WHERE id = ?").get(id);
      if (paidBillDetails && paidBillDetails.is_settlement_bill) {
          const patientId = paidBillDetails.settlement_for_patient_id;
          db.prepare(`UPDATE billing SET status = 'paid', paid_amount = total_amount WHERE patient_id = ? AND id != ? AND status IN ('pending', 'partial')`).run(patientId, id);
      }
    }
  });

  try {
    tx();
    res.json({ status: newStatus, paidAmount: newPaid });
  } catch(e) {
    res.status(500).json({ error: e.message });
  }
};

exports.cancelService = (req, res) => {
  const { id } = req.params;
  const tx = db.transaction(() => {
    db.prepare("UPDATE appointments SET status = 'cancelled' WHERE bill_id = ?").run(id);
    db.prepare("UPDATE lab_requests SET status = 'cancelled' WHERE bill_id = ?").run(id);
