exports.processRefund = (req, res) => {
  const { id } = req.params;
  const { amount, reason, date, method } = req.body;
  const tx = db.transaction(() => {
    const bill = db.prepare('SELECT * FROM billing WHERE id = ?').get(id);
    if (!bill) throw new Error('Bill not found');
    if (amount > bill.paid_amount) throw new Error('Refund amount exceeds paid amount');
    const newPaid = bill.paid_amount - amount;
    let newStatus = 'partial';
    if (newPaid <= 0) newStatus = 'refunded'; 
    else if (newPaid >= bill.total_amount) newStatus = 'paid';
    db.prepare('UPDATE billing SET paid_amount = ?, status = ? WHERE id = ?').run(newPaid, newStatus, id);
    db.prepare(`INSERT INTO transactions (type, category, amount, method, reference_id, details, date, description) VALUES ('expense', 'Refund', ?, ?, ?, ?, ?, ?)`).run(amount, method || 'Cash', id, JSON.stringify({ reason }), date || new Date().toISOString(), `Refund for Bill #${bill.bill_number}: ${reason}`);
  });
  try {
    tx();
    res.json({ success: true });
  } catch (err) {
    res.status(400).json({ error: err.message });
  }
};

exports.getTransactions = (req, res) => {
  try {
    const transactions = db.prepare('SELECT * FROM transactions ORDER BY date DESC').all();
    res.json(transactions.map(t => {
      let details = {};
      try { details = JSON.parse(t.details); } catch(e) {}
      return { ...t, details };
    }));
  } catch (err) { res.status(500).json({ error: err.message }); }
};

exports.addExpense = (req, res) => {
  const { category, amount, method, description, date } = req.body;
  try {
    const info = db.prepare(`INSERT INTO transactions (type, category, amount, method, date, description) VALUES ('expense', ?, ?, ?, ?, ?)`).run(category, amount, method, date || new Date().toISOString(), description);
    res.json({ id: info.lastInsertRowid, success: true });
  } catch(e) { res.status(500).json({ error: e.message }); }
};

exports.updateExpense = (req, res) => {
  const { id } = req.params;
  const { category, amount, method, description, date } = req.body;
  try {
    const result = db.prepare(`UPDATE transactions SET category = ?, amount = ?, method = ?, date = ?, description = ? WHERE id = ? AND type = 'expense'`).run(category, amount, method, date, description, id);
    if (result.changes === 0) return res.status(404).json({ error: 'Expense record not found or not editable' });
    res.json({ success: true });
  } catch(e) { res.status(500).json({ error: e.message }); }
};

import React from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: React.ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

/**
 * ErrorBoundary component to catch rendering errors in the component tree.
 */
export class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  // FIX: Reverted to constructor-based state initialization and method binding.
  // The previous implementation using class properties was causing 'this' context issues 
  // (e.g., 'this.setState' not found), likely due to a build tool configuration that
  // doesn't fully support class properties. This approach is more robust.
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = {
      hasError: false,
      error: null,
    };
    this.handleReload = this.handleReload.bind(this);
  }

  /**
   * Static method to update state when an error occurs during rendering.
   */
  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  /**
   * Lifecycle method to log error details.
   */
  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  /**
   * Resets the error state to allow the application to attempt re-rendering.
   */
  handleReload() {
    this.setState({ hasError: false, error: null });
  }

  render(): React.ReactNode {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-900 p-4">
          <div className="bg-white dark:bg-slate-800 p-8 rounded-2xl shadow-xl max-w-md w-full text-center border border-slate-200 dark:border-slate-700">
            <div className="w-16 h-16 bg-red-100 dark:bg-red-900/20 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600 dark:text-red-400">
              <AlertTriangle size={32} />
            </div>
            <h1 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Something went wrong</h1>
            <p className="text-slate-500 dark:text-slate-400 mb-6 text-sm">
              The application encountered an unexpected error.
            </p>

            {this.state.error && (
                <div className="bg-slate-100 dark:bg-slate-950 p-3 rounded-lg text-left text-xs font-mono text-red-600 dark:text-red-400 overflow-auto max-h-32 mb-6">
                    {this.state.error.toString()}
                </div>
            )}

            <button 
              onClick={this.handleReload}
              className="inline-flex items-center justify-center gap-2 px-6 py-3 bg-primary-600 hover:bg-primary-700 text-white font-semibold rounded-xl transition-all w-full"
            >
              <RefreshCw size={18} />
              Try Again
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}
